import { AXTranslation, AXTranslationLoader, AXTranslationLoaderOptions } from '@acorex/core/translation';
import { HttpClient } from '@angular/common/http';
import { inject, Injectable } from '@angular/core';
import { first, Observable } from 'rxjs';

@Injectable()
export class AppTranslationLoader implements AXTranslationLoader {
  private http = inject(HttpClient);

  load(options: AXTranslationLoaderOptions): Observable<AXTranslation> {
    return this.http
      .get<AXTranslation>(`/assets/i18n/${options.lang}/${options.scope}.json`)
      .pipe(first());
  }
}

import { ApplicationConfig, importProvidersFrom } from '@angular/core';
import { provideHttpClient } from '@angular/common/http';
import {
  AXTranslationModule,
  AX_TRANSLATION_CONFIG,
  AX_TRANSLATION_LOADER,
  translationConfig,
} from '@acorex/core/translation';
import { AppTranslationLoader } from './app.loaders';

export const appConfig: ApplicationConfig = {
  providers: [
    provideHttpClient(),
    importProvidersFrom(AXTranslationModule),
    { provide: AX_TRANSLATION_LOADER, useClass: AppTranslationLoader },
    {
      provide: AX_TRANSLATION_CONFIG,
      useValue: translationConfig({
        defaults: { lang: 'en-US', scope: 'acorex' },
        preload: {
          langs: ['en-US', 'fa-IR'],
          scopes: ['acorex', 'common'],
        },
      }),
    },
  ],
};

import { AsyncPipe } from '@angular/common';
import { Component } from '@angular/core';
import { AXTranslatorPipe } from '@acorex/core/translation';

@Component({
  imports: [AsyncPipe, AXTranslatorPipe],
  templateUrl: './product.page.html',
})
export class ProductPage {}

import { inject, Injectable } from '@angular/core';
import { AXTranslationService } from '@acorex/core/translation';

@Injectable({ providedIn: 'root' })
export class NotificationService {
  private translation = inject(AXTranslationService);

  async showMore(count: number) {
    const title = await this.translation.translateAsync(
      '@acorex:common.notifications.more',
      { params: { count } },
    );
    console.log(title);
  }

  getTitleSync() {
    return this.translation.translateSync('@acorex:validation.messages.title', {
      waitForLoad: true,
      timeoutMs: 200,
    });
  }
}

import { AsyncPipe } from '@angular/common';
import { Component, inject } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { AXLocaleService } from '@acorex/core/locale';
import { AXTranslationService, AXTranslatorPipe } from '@acorex/core/translation';

@Component({
  imports: [AsyncPipe, AXTranslatorPipe],
  template: `
    <button type="button" (click)="setFa()">FA</button>
    <button type="button" (click)="setEn()">EN</button>
    <p>{{ '@acorex:common.actions.save' | translate | async }}</p>
  `,
})
export class LanguageSwitcherComponent {
  private locale = inject(AXLocaleService);
  private translation = inject(AXTranslationService);

  constructor() {
    this.translation.langChanges$
      .pipe(takeUntilDestroyed())
      .subscribe((lang) => console.log('Active lang:', lang));
  }

  setFa() {
    this.locale.setProfile('fa-IR'); // also updates translation service
  }

  setEn() {
    this.locale.setProfile('en-US');
  }
}

import {
  AXMultiLanguageMap,
  AXTranslationService,
  createMultiLanguageString,
  resolveMultiLanguageString,
} from '@acorex/core/translation';
import { inject } from '@angular/core';

const label: AXMultiLanguageMap = createMultiLanguageString('Save', 'ذخیره');
// { 'en-US': 'Save', 'fa-IR': 'ذخیره' }

function resolveLabel() {
  const translation = inject(AXTranslationService);
  const locale = translation.getActiveLang();

  // Direct resolve (no JSON lookup)
  resolveMultiLanguageString(label, locale);

  // Or translate via service (pipe-compatible)
  return translation.translateAsync(label);
}

import { Routes } from '@angular/router';
import { loadTranslationScope } from '@acorex/core/translation';

export const routes: Routes = [
  {
    path: 'theme-builder',
    loadChildren: () => import('./theme-builder/routes'),
    resolve: { translations: loadTranslationScope },
    data: { scope: 'common' },
  },
  {
    path: 'admin',
    loadChildren: () => import('./admin/routes'),
    resolve: { translations: loadTranslationScope },
    data: { scope: ['common', 'admin'] }, // multiple scopes
  },
];

import { Component } from '@angular/core';
import { AsyncPipe } from '@angular/common';
import { AXTranslatorDirective } from '@acorex/core/translation';

@Component({
  imports: [AsyncPipe, AXTranslatorDirective],
  templateUrl: './custom-block.component.html',
})
export class CustomBlockComponent {}
